package com.google.gson;
import static com.google.gson.Gson.DEFAULT_COMPLEX_MAP_KEYS;
import static com.google.gson.Gson.DEFAULT_DATE_PATTERN;
import static com.google.gson.Gson.DEFAULT_ESCAPE_HTML;
import static com.google.gson.Gson.DEFAULT_JSON_NON_EXECUTABLE;
import static com.google.gson.Gson.DEFAULT_LENIENT;
import static com.google.gson.Gson.DEFAULT_NUMBER_TO_NUMBER_STRATEGY;
import static com.google.gson.Gson.DEFAULT_OBJECT_TO_NUMBER_STRATEGY;
import static com.google.gson.Gson.DEFAULT_PRETTY_PRINT;
import static com.google.gson.Gson.DEFAULT_SERIALIZE_NULLS;
import static com.google.gson.Gson.DEFAULT_SPECIALIZE_FLOAT_VALUES;
import static com.google.gson.Gson.DEFAULT_USE_JDK_UNSAFE;
import com.google.gson.annotations.Since;
import com.google.gson.annotations.Until;
import com.google.gson.internal.$Gson$Preconditions;
import com.google.gson.internal.bind.DefaultDateTypeAdapter;
import com.google.gson.internal.bind.TreeTypeAdapter;
import com.google.gson.internal.sql.SqlTypesSupport;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonWriter;
import java.lang.reflect.Type;
import java.util.ArrayList;
import java.util.Collections;
import java.util.Date;
import java.util.HashMap;
import java.util.LinkedList;
import java.util.Objects;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.Excluder;
import com.google.gson.internal.bind.TypeAdapters;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.text.DateFormat;
import java.util.List;
import java.util.Map;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void testConstructor_withGsonCopiesAllFields() throws Exception {
    // Create a mock Gson with custom field values
    Gson gson = mock(Gson.class);
    Excluder excluderMock = Excluder.DEFAULT;
    when(gson.excluder).thenReturn(excluderMock);
    when(gson.fieldNamingStrategy).thenReturn(FieldNamingPolicy.IDENTITY);
    when(gson.serializeNulls).thenReturn(true);
    when(gson.complexMapKeySerialization).thenReturn(true);
    when(gson.generateNonExecutableJson).thenReturn(true);
    when(gson.htmlSafe).thenReturn(true);
    when(gson.prettyPrinting).thenReturn(true);
    when(gson.lenient).thenReturn(true);
    when(gson.serializeSpecialFloatingPointValues).thenReturn(true);
    when(gson.longSerializationPolicy).thenReturn(LongSerializationPolicy.STRING);
    when(gson.datePattern).thenReturn("yyyy-MM-dd");
    when(gson.dateStyle).thenReturn(DateFormat.SHORT);
    when(gson.timeStyle).thenReturn(DateFormat.MEDIUM);
    when(gson.useJdkUnsafe).thenReturn(true);
    when(gson.objectToNumberStrategy).thenReturn(ToNumberPolicy.LAZILY_PARSED_NUMBER);
    when(gson.numberToNumberStrategy).thenReturn(ToNumberPolicy.LONG_OR_DOUBLE);

    // Setup builderFactories and builderHierarchyFactories fields on gson
    List<TypeAdapterFactory> builderFactories = List.of(TypeAdapters.STRING_FACTORY);
    List<TypeAdapterFactory> builderHierarchyFactories = List.of(TypeAdapters.INTEGER_FACTORY);
    Field builderFactoriesField = Gson.class.getDeclaredField("builderFactories");
    builderFactoriesField.setAccessible(true);
    builderFactoriesField.set(gson, builderFactories);
    Field builderHierarchyFactoriesField = Gson.class.getDeclaredField("builderHierarchyFactories");
    builderHierarchyFactoriesField.setAccessible(true);
    builderHierarchyFactoriesField.set(gson, builderHierarchyFactories);

    // Setup reflectionFilters field on gson
    LinkedList<ReflectionAccessFilter> reflectionFilters = new LinkedList<>();
    Field reflectionFiltersField = Gson.class.getDeclaredField("reflectionFilters");
    reflectionFiltersField.setAccessible(true);
    reflectionFiltersField.set(gson, reflectionFilters);

    GsonBuilder builder = new GsonBuilder(gson);

    // Verify fields copied
    Field excluderField = GsonBuilder.class.getDeclaredField("excluder");
    excluderField.setAccessible(true);
    assertSame(excluderMock, excluderField.get(builder));

    Field fieldNamingPolicyField = GsonBuilder.class.getDeclaredField("fieldNamingPolicy");
    fieldNamingPolicyField.setAccessible(true);
    assertEquals(FieldNamingPolicy.IDENTITY, fieldNamingPolicyField.get(builder));

    Field serializeNullsField = GsonBuilder.class.getDeclaredField("serializeNulls");
    serializeNullsField.setAccessible(true);
    assertTrue((Boolean) serializeNullsField.get(builder));

    Field complexMapKeySerializationField = GsonBuilder.class.getDeclaredField("complexMapKeySerialization");
    complexMapKeySerializationField.setAccessible(true);
    assertTrue((Boolean) complexMapKeySerializationField.get(builder));

    Field generateNonExecutableJsonField = GsonBuilder.class.getDeclaredField("generateNonExecutableJson");
    generateNonExecutableJsonField.setAccessible(true);
    assertTrue((Boolean) generateNonExecutableJsonField.get(builder));

    Field escapeHtmlCharsField = GsonBuilder.class.getDeclaredField("escapeHtmlChars");
    escapeHtmlCharsField.setAccessible(true);
    assertTrue((Boolean) escapeHtmlCharsField.get(builder));

    Field prettyPrintingField = GsonBuilder.class.getDeclaredField("prettyPrinting");
    prettyPrintingField.setAccessible(true);
    assertTrue((Boolean) prettyPrintingField.get(builder));

    Field lenientField = GsonBuilder.class.getDeclaredField("lenient");
    lenientField.setAccessible(true);
    assertTrue((Boolean) lenientField.get(builder));

    Field serializeSpecialFloatingPointValuesField = GsonBuilder.class.getDeclaredField("serializeSpecialFloatingPointValues");
    serializeSpecialFloatingPointValuesField.setAccessible(true);
    assertTrue((Boolean) serializeSpecialFloatingPointValuesField.get(builder));

    Field longSerializationPolicyField = GsonBuilder.class.getDeclaredField("longSerializationPolicy");
    longSerializationPolicyField.setAccessible(true);
    assertEquals(LongSerializationPolicy.STRING, longSerializationPolicyField.get(builder));

    Field datePatternField = GsonBuilder.class.getDeclaredField("datePattern");
    datePatternField.setAccessible(true);
    assertEquals("yyyy-MM-dd", datePatternField.get(builder));

    Field dateStyleField = GsonBuilder.class.getDeclaredField("dateStyle");
    dateStyleField.setAccessible(true);
    assertEquals(DateFormat.SHORT, dateStyleField.get(builder));

    Field timeStyleField = GsonBuilder.class.getDeclaredField("timeStyle");
    timeStyleField.setAccessible(true);
    assertEquals(DateFormat.MEDIUM, timeStyleField.get(builder));

    Field useJdkUnsafeField = GsonBuilder.class.getDeclaredField("useJdkUnsafe");
    useJdkUnsafeField.setAccessible(true);
    assertTrue((Boolean) useJdkUnsafeField.get(builder));

    Field objectToNumberStrategyField = GsonBuilder.class.getDeclaredField("objectToNumberStrategy");
    objectToNumberStrategyField.setAccessible(true);
    assertEquals(ToNumberPolicy.LAZILY_PARSED_NUMBER, objectToNumberStrategyField.get(builder));

    Field numberToNumberStrategyField = GsonBuilder.class.getDeclaredField("numberToNumberStrategy");
    numberToNumberStrategyField.setAccessible(true);
    assertEquals(ToNumberPolicy.LONG_OR_DOUBLE, numberToNumberStrategyField.get(builder));

    Field factoriesField = GsonBuilder.class.getDeclaredField("factories");
    factoriesField.setAccessible(true);
    List<?> factories = (List<?>) factoriesField.get(builder);
    assertTrue(factories.containsAll(builderFactories));

    Field hierarchyFactoriesField = GsonBuilder.class.getDeclaredField("hierarchyFactories");
    hierarchyFactoriesField.setAccessible(true);
    List<?> hierarchyFactories = (List<?>) hierarchyFactoriesField.get(builder);
    assertTrue(hierarchyFactories.containsAll(builderHierarchyFactories));

    Field reflectionFiltersFieldBuilder = GsonBuilder.class.getDeclaredField("reflectionFilters");
    reflectionFiltersFieldBuilder.setAccessible(true);
    LinkedList<?> reflectionFiltersBuilder = (LinkedList<?>) reflectionFiltersFieldBuilder.get(builder);
    assertTrue(reflectionFiltersBuilder.containsAll(reflectionFilters));
  }

}
